import re
p="/Users/gbang/Downloads/algora/workspace/03146622-c043-4708-8846-04a4be7e0574_hld/_response.md"
src=open(p).read()
lines=src.split("\n")
in_block=False
problems=[]
risky=['(',')',':',';','/','\\','<','>','{','}']
for i,l in enumerate(lines,1):
    s=l.strip()
    if s.startswith("```mermaid"): in_block=True; continue
    if in_block and s=="```": in_block=False; continue
    if not in_block: continue
    if s.startswith("classDef") or s.startswith("class ") or s.startswith("subgraph") or s.startswith("flowchart") or s=="end":
        # still check subgraph titles inside quotes
        if s.startswith("subgraph"):
            for m in re.findall(r'\["([^"]*)"\]', l):
                bad=[c for c in risky if c in m]
                if bad: problems.append((i,"subgraph-title",m,bad))
        continue
    # 1) edge labels |"..."| or |...|
    for m in re.findall(r'\|"([^"]*)"\|', l):
        bad=[c for c in risky if c in m]
        if bad: problems.append((i,"edge-quoted",m,bad))
    for m in re.findall(r'\|([^"|]+)\|', l):  # unquoted edge labels
        bad=[c for c in risky if c in m]
        if bad: problems.append((i,"edge-unquoted",m,bad))
    # 2) node labels in ["..."]
    for m in re.findall(r'\["([^"]*)"\]', l):
        bad=[c for c in risky if c in m]
        if bad: problems.append((i,"node-quoted",m,bad))
    # 3) node labels in plain [text] (no quotes)
    for m in re.findall(r'\[([^\["\]\(]+)\]', l):
        bad=[c for c in risky if c in m]
        if bad: problems.append((i,"node-plain",m,bad))
    # 4) cylinder [(...)]
    for m in re.findall(r'\[\(([^)]*)\)\]', l):
        bad=[c for c in risky if c in m]
        if bad: problems.append((i,"cylinder",m,bad))
    # 5) double-bracket [[...]]
    for m in re.findall(r'\[\[([^\]]*)\]\]', l):
        bad=[c for c in risky if c in m]
        if bad: problems.append((i,"subroutine",m,bad))

if not problems:
    print("NO breaking chars found inside any LABEL/EDGE-TEXT content.")
else:
    for pr in problems:
        print("PROBLEM:", pr)
